```python
class _ActiveRequestsObserver(BaseplateObserver, _Reporter):
    def __init__(self) -> None:
        self.live_requests: Dict[int, Set[int]] = defaultdict(set)

    def add(self, trace_id: int) -> int:
        key = int(time.time())
        self.live_requests[key].add(trace_id)
        return key

    def remove(self, timestamp: int, trace_id: int) -> None:
        if timestamp in self.live_requests:
            self.live_requests[timestamp].remove(trace_id)

    def on_server_span_created(self, context: RequestContext, server_span: ServerSpan) -> None:
        observer = _ActiveRequestsServerSpanObserver(self, server_span.trace_id)
        server_span.register(observer)

    def report(self, batch: metrics.Batch) -> None:
        cutoff = int(time.time()) - 15
        for expired in filter(lambda k: k <= cutoff, self.live_requests.keys()):
            self.live_requests.pop(expired, None)
        batch.gauge("active_requests").replace(len(list(itertools.chain(self.live_requests.values()))))
```

Here we are adding a bunch of APIs for channel related info. To have a more flexible way and reduce the number of `otPlatRadio` APIs for this purpose I have a suggestion:
